import { CROSS_REFS_2 } from './crossReferences2';

export function getCrossRefs(bookName, chapter, verse) {
  const key = `${bookName} ${chapter}:${verse}`;
  return CROSS_REFS[key] || CROSS_REFS_2[key] || [];
}

// ── Full cross-reference database (lazy-loaded) ──────────────
let _fullDb = null;
let _loadPromise = null;

function loadFullDb() {
  if (_fullDb) return Promise.resolve(_fullDb);
  if (_loadPromise) return _loadPromise;

  // In Electron production, use IPC (file:// fetch is blocked)
  // In dev / web, fall back to fetch
  const ipc = typeof window !== 'undefined' && window.seferAPI?.crossRefsRead;
  _loadPromise = (ipc
    ? ipc().then((json) => JSON.parse(json))
    : fetch('./crossrefs_full.json').then((r) => r.json())
  )
    .then((data) => { _fullDb = data; return data; })
    .catch(() => { _fullDb = {}; return {}; });

  return _loadPromise;
}

export async function getCrossRefsAsync(bookName, chapter, verse) {
  const key = `${bookName} ${chapter}:${verse}`;
  // Return curated refs immediately if available
  const curated = CROSS_REFS[key] || CROSS_REFS_2[key];
  if (curated) return curated;
  // Otherwise query the full database
  const db = await loadFullDb();
  return db[key] || [];
}

// Kick off loading in background so first open is fast
if (typeof window !== 'undefined') loadFullDb();
